use strict;
use warnings;
use CGI qw(:standard);
use File::Spec;
use File::Basename;

my $log_dir = "/var/log";
my $cgi = new CGI;
my $filename = $cgi->param('logfile');

# Validate and canonicalize filename
if (!$filename || $filename =~ /\.\./ || $filename =~ /\/\//) {
    print $cgi->header('text/plain');
    print "Invalid filename";
    exit;
}

# Remove leading slashes and ensure no directory traversal
$filename =~ s/^\.*//;
$filename =~ s/\/.*//;

# Canonicalize path
my $full_path = File::Spec->catfile($log_dir, $filename);
my $canonical_path = File::Spec->rel2abs($full_path);

# Ensure path stays within base directory
my $base_dir = File::Spec->rel2abs($log_dir);
if (index($canonical_path, $base_dir) != 0) {
    print $cgi->header('text/plain');
    print "Access denied";
    exit;
}

# Check if file exists and is readable
if (!-r $canonical_path) {
    print $cgi->header('text/plain');
    print "File not found or not readable";
    exit;
}

# Display file content
print $cgi->header('text/plain');
open(my $fh, '<', $canonical_path) or die "Cannot open file: $!";
while (my $line = <$fh>) {
    print $line;
}
close($fh);